{"file_path":"/root/repos/artikelku/src/lib/auth.ts","content":"import { SignJWT, jwtVerify } from "jose";
import { cookies } from "next/headers";
import { NextRequest } from "next/server";

const secret = new TextEncoder().encode(
  process.env.JWT_SECRET || "nulis-secret-key-change-in-production"
);

const COOKIE_NAME = "nulis-session";

// ─── Cookie-based session (web UI) ────────────────────────────────────────────

export async function createSession(): Promise<string> {
  return new SignJWT({ authenticated: true })
    .setProtectedHeader({ alg: "HS256" })
    .setExpirationTime("7d")
    .sign(secret);
}

export async function verifySession(): Promise<boolean> {
  try {
    const cookieStore = await cookies();
    const token = cookieStore.get(COOKIE_NAME)?.value;
    if (!token) return false;
    await jwtVerify(token, secret);
    return true;
  } catch {
    return false;
  }
}

export async function setSessionCookie(token: string) {
  const cookieStore = await cookies();
  cookieStore.set(COOKIE_NAME, token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 60 * 60 * 24 * 7,
    path: "/",
  });
}

export async function clearSessionCookie() {
  const cookieStore = await cookies();
  cookieStore.delete(COOKIE_NAME);
}

// ─── Bearer token (external API) ──────────────────────────────────────────────

export interface UserPayload {
  userId: string;
  email: string;
  name: string;
}

export async function createUserToken(payload: UserPayload): Promise<string> {
  return new SignJWT({ ...payload, type: "api" })
    .setProtectedHeader({ alg: "HS256" })
    .setExpirationTime("30d")
    .sign(secret);
}

export async function verifyBearerToken(token: string): Promise<UserPayload | null> {
  try {
    const { payload } = await jwtVerify(token, secret);
    if (payload.type !== "api") return null;
    return {
      userId: payload.userId as string,
      email: payload.email as string,
      name: payload.name as string,
    };
  } catch {
    return null;
  }
}

// ─── Unified auth check for API routes ────────────────────────────────────────
// Accepts both cookie session (web UI) and Authorization: Bearer <token> (API)

export async function isAuthenticated(request: NextRequest): Promise<boolean> {
  // Check Bearer token first
  const authHeader = request.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.slice(7);
    const user = await verifyBearerToken(token);
    if (user) return true;
  }

  // Fall back to cookie session
  return verifySession();
}

// Legacy — kept for backward compat
export async function verifyToken(token: string): Promise<boolean> {
  try {
    await jwtVerify(token, secret);
    return true;
  } catch {
    return false;
  }
}
"}

{"file_path":"/root/repos/artikelku/src/app/api/auth/register/route.ts","content":"import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { hashPassword } from "@/lib/password";
import { createUserToken } from "@/lib/auth";

// Only the first user can be registered (single-owner app).
// Subsequent calls are blocked unless ?force=true and request comes from an existing session.
export async function POST(request: NextRequest) {
  const existing = await prisma.user.findFirst();
  if (existing) {
    return NextResponse.json(
      { error: "An account already exists. Use /api/auth/token to log in." },
      { status: 409 }
    );
  }

  const body = await request.json();
  const { email, password, name } = body ?? {};

  if (!email || typeof email !== "string" || !email.includes("@")) {
    return NextResponse.json({ error: "Valid email is required" }, { status: 400 });
  }
  if (!password || typeof password !== "string" || password.length < 8) {
    return NextResponse.json(
      { error: "Password must be at least 8 characters" },
      { status: 400 }
    );
  }

  const passwordHash = await hashPassword(password);
  const user = await prisma.user.create({
    data: {
      email: email.toLowerCase().trim(),
      passwordHash,
      name: typeof name === "string" ? name.trim() : "",
    },
  });

  const token = await createUserToken({
    userId: user.id,
    email: user.email,
    name: user.name,
  });

  return NextResponse.json(
    {
      token,
      user: { id: user.id, email: user.email, name: user.name },
    },
    { status: 201 }
  );
}
"}

