    const task = loadRestartTask();
    if (!task) return;
    clearRestartTask();

    const config = this.configStore.getIntegrations().telegram;
    const chatId = config.allowedUserId;
    if (!chatId || !this.bot) return;

    const elapsed = Math.round((Date.now() - new Date(task.timestamp).getTime()) / 1000);
    const who = task.minionId ? `*${task.minionId}*` : "Server";
    const msg =
      `✅ *Restart selesai* (${elapsed}s downtime)\n\n` +
      `${who} tadi lagi ngerjain:\n_${task.context}_`;

    await this.bot.api
      .sendMessage(chatId, msg, { parse_mode: "Markdown" })
      .catch(() => this.bot?.api.sendMessage(chatId, msg.replace(/[*_]/g, "")));
  }"}

