{"file_path":"/root/minion/packages/web/src/components/Scene/Minion.tsx","content":"import { useRef, useState, useCallback, useEffect } from "react";
import { useFrame } from "@react-three/fiber";
import { Html } from "@react-three/drei";
import * as THREE from "three";
import type { MinionState } from "../../types";
import { useStore } from "../../store";

// Global minion positions for separation steering
const minionPositions: Map<string, THREE.Vector3> = new Map();
export function getMinionPositions() { return minionPositions; }

// Waypoints around the joglo
const WAYPOINTS: [number, number][] = [
  [-3, -3], [0, -3], [3, -3],
  [-2, 0], [2, 0], [0, 0],
  [-4, 3], [4, 3], [0, 4],
  [-5, -1], [5, -1],
  [0, 5],
  [-3, 4], [3, 4],
];

const DESK_POSITIONS: [number, number][] = [
  [-4.5, -5.3], [-1.5, -5.3], [1.5, -5.3], [4.5, -5.3],
];

type AnimState = "idle" | "walking" | "working";
type Expression = "neutral" | "focused" | "happy" | "sad";

interface MinionProps {
  minion: MinionState;
  startPosition: [number, number];
}

// ─── PBR skin material helper ──────────────────────────────
function skinMat(color: string, roughness = 0.75) {
  return <meshPhysicalMaterial color={color} roughness={roughness} metalness={0} reflectivity={0.1} />;
}
function clothMat(color: string) {
  return <meshPhysicalMaterial color={color} roughness={0.85} metalness={0} />;
}

export function Minion({ minion, startPosition }: MinionProps) {
  const groupRef = useRef<THREE.Group>(null);
  const [hovered, setHovered] = useState(false);
  const [expression, setExpression] = useState<Expression>("neutral");
  const { selectedMinionId, selectMinion } = useStore();
  const isSelected = selectedMinionId === minion.id;
  const prevStatus = useRef(minion.status);

  useEffect(() => {
    if (minion.status === "working") {
      setExpression("focused");
    } else if (minion.status === "error") {
      setExpression("sad");
      setTimeout(() => setExpression("neutral"), 5000);
    } else if (prevStatus.current === "working" && minion.status === "idle") {
      setExpression("happy");
      setTimeout(() => setExpression("neutral"), 4000);
    } else {
      setExpression("neutral");
    }
    prevStatus.current = minion.status;
  }, [minion.status]);

  const moveState = useRef({
    position: new THREE.Vector3(startPosition[0], 0, startPosition[1]),
    target: new THREE.Vector3(startPosition[0], 0, startPosition[1]),
    rotation: 0,
    targetRotation: 0,
    animState: "idle" as AnimState,
    idleTimer: Math.random() * 3 + 1,
    walkSpeed: 0.8 + Math.random() * 0.4,
    _dir: new THREE.Vector3(),
    _push: new THREE.Vector3(),
  });

  const pickNewTarget = useCallback(() => {
    const state = moveState.current;
    if (minion.status === "working") {
      const desk = DESK_POSITIONS[Math.floor(Math.random() * DESK_POSITIONS.length)];
      state.target.set(desk[0], 0, desk[1]);
    } else {
      const wp = WAYPOINTS[Math.floor(Math.random() * WAYPOINTS.length)];
      state.target.set(wp[0], 0, wp[1]);
    }
    const dx = state.target.x - state.position.x;
    const dz = state.target.z - state.position.z;
    state.targetRotation = Math.atan2(dx, dz);
    state.animState = "walking";
  }, [minion.status]);

  useEffect(() => {
    if (minion.status === "working") pickNewTarget();
  }, [minion.status, pickNewTarget]);

  useEffect(() => {
    return () => { minionPositions.delete(minion.id); };
  }, [minion.id]);

  useFrame(({ clock }, delta) => {
    if (!groupRef.current) return;
    const state = moveState.current;
    const t = clock.getElapsedTime();

    if (state.animState === "idle") {
      state.idleTimer -= delta;
      if (state.idleTimer <= 0) pickNewTarget();
    } else if (state.animState === "walking") {
      const rotDiff = state.targetRotation - state.rotation;
      const normalizedDiff = ((rotDiff + Math.PI) % (Math.PI * 2)) - Math.PI;
      state.rotation += normalizedDiff * Math.min(1, delta * 5);

      const dir = state._dir.subVectors(state.target, state.position).normalize();
      const dist = state.position.distanceTo(state.target);

      if (dist > 0.15) {
        state.position.add(dir.multiplyScalar(Math.min(state.walkSpeed * delta, dist)));
      } else {
        if (minion.status === "working") {
          state.animState = "working";
          state.targetRotation = Math.PI;
          state.rotation = Math.PI;
        } else {
          state.animState = "idle";
          state.idleTimer = 2 + Math.random() * 5;
        }
      }
    } else if (state.animState === "working" && minion.status !== "working") {
      state.animState = "idle";
      state.idleTimer = 1;
    }

    // Separation steering
    for (const [otherId, otherPos] of minionPositions) {
      if (otherId === minion.id) continue;
      const dist = state.position.distanceTo(otherPos);
      if (dist < 0.8 && dist > 0.01) {
        state._push.subVectors(state.position, otherPos).normalize();
        state.position.add(state._push.multiplyScalar(0.02));
      }
    }

    minionPositions.set(minion.id, state.position.clone());
    groupRef.current.position.copy(state.position);
    groupRef.current.rotation.y = state.rotation;

    if (state.animState === "walking") {
      groupRef.current.position.y = Math.abs(Math.sin(t * 6)) * 0.04;
    } else {
      groupRef.current.position.y = 0;
    }
  });

  return (
    <group
      ref={groupRef}
      onClick={(e) => { e.stopPropagation(); selectMinion(isSelected ? null : minion.id); }}
      onPointerOver={(e) => { e.stopPropagation(); setHovered(true); document.body.style.cursor = "pointer"; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = "default"; }}
    >
      <PunakawanBody
        characterId={minion.id}
        outfit={minion.outfit}
        animState={moveState.current.animState}
        isWorking={minion.status === "working"}
        hovered={hovered}
        isSelected={isSelected}
        accentColor={minion.color}
        expression={expression}
      />

      {/* Floating label — glassmorphism */}
      <Html position={[0, getLabelHeight(minion.id), 0]} center distanceFactor={10} style={{ pointerEvents: "none" }}>
        <div style={{
          background: minion.status === "working"
            ? "rgba(80, 30, 0, 0.82)"
            : "rgba(255, 248, 235, 0.78)",
          backdropFilter: "blur(12px)",
          WebkitBackdropFilter: "blur(12px)",
          color: minion.status === "working" ? "#FFD9A0" : "#3E2000",
          padding: "5px 14px",
          borderRadius: "12px",
          fontSize: "11px",
          fontFamily: "'Inter', sans-serif",
          textAlign: "center",
          whiteSpace: "nowrap",
          boxShadow: `0 4px 16px rgba(0,0,0,0.25), inset 0 1px 0 rgba(255,255,255,0.3)`,
          border: `1.5px solid ${minion.status === "working" ? "rgba(255,180,60,0.5)" : minion.color + "88"}`,
        }}>
          <div style={{ fontWeight: 700, fontSize: "12px", letterSpacing: "0.3px" }}>{minion.name}</div>
          <div style={{ fontSize: "9px", opacity: 0.65, marginTop: "1px" }}>{minion.role}</div>
          {minion.status === "working" && (
            <div style={{
              display: "flex", alignItems: "center", justifyContent: "center",
              gap: "4px", marginTop: "3px",
            }}>
              <span style={{
                width: 5, height: 5, borderRadius: "50%",
                background: "#FFB347",
                boxShadow: "0 0 6px #FFB347",
                animation: "pulse 1.2s ease-in-out infinite",
              }} />
              <span style={{ fontSize: "8px", opacity: 0.8 }}>working</span>
            </div>
          )}
        </div>
      </Html>

      {isSelected && <SelectionRing color={minion.color} />}
      {hovered && !isSelected && <HoverGlow color={minion.color} />}
    </group>
  );
}

function getLabelHeight(id: string): number {
  switch (id) {
    case "semar": return 1.9;
    case "gareng": return 2.1;
    case "petruk": return 2.7;
    case "bagong": return 2.0;
    default: return 2.2;
  }
}

function SelectionRing({ color }: { color: string }) {
  const ref = useRef<THREE.Mesh>(null);
  useFrame(({ clock }) => {
    if (ref.current) {
      ref.current.rotation.z = clock.getElapsedTime() * 0.8;
      (ref.current.material as THREE.MeshBasicMaterial).opacity =
        0.45 + Math.sin(clock.getElapsedTime() * 3) * 0.2;
    }
  });
  return (
    <mesh ref={ref} rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.02, 0]}>
      <ringGeometry args={[0.58, 0.72, 48]} />
      <meshBasicMaterial color={color} transparent opacity={0.6} />
    </mesh>
  );
}

function HoverGlow({ color }: { color: string }) {
  const ref = useRef<THREE.Mesh>(null);
  useFrame(({ clock }) => {
    if (ref.current) {
      (ref.current.material as THREE.MeshBasicMaterial).opacity =
        0.15 + Math.sin(clock.getElapsedTime() * 4) * 0.05;
    }
  });
  return (
    <mesh ref={ref} rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.01, 0]}>
      <circleGeometry args={[0.75, 32]} />
      <meshBasicMaterial color={color} transparent opacity={0.15} />
    </mesh>
  );
}

// ─── Realistic Eyes (3-layer) ──────────────────────────────
function RealisticEye({ x, y, z, size = 0.032, irisColor = "#4a7c59", expression }: {
  x: number; y: number; z: number; size?: number; irisColor?: string; expression: Expression;
}) {
  const scaleY = expression === "focused" ? 0.45 : expression === "happy" ? 0.75 : expression === "sad" ? 0.8 : 1;
  return (
    <group position={[x, y, z]} scale={[1, scaleY, 1]}>
      {/* Sclera */}
      <mesh>
        <sphereGeometry args={[size, 12, 8]} />
        <meshPhysicalMaterial color="#F8F4EF" roughness={0.1} reflectivity={0.8} />
      </mesh>
      {/* Iris */}
      <mesh position={[0, 0, size * 0.6]}>
        <sphereGeometry args={[size * 0.65, 10, 7]} />
        <meshPhysicalMaterial color={irisColor} roughness={0.2} metalness={0.1} />
      </mesh>
      {/* Pupil */}
      <mesh position={[0, 0, size * 1.1]}>
        <sphereGeometry args={[size * 0.32, 8, 6]} />
        <meshStandardMaterial color="#0a0a0a" roughness={0.0} />
      </mesh>
      {/* Catchlight */}
      <mesh position={[size * 0.18, size * 0.2, size * 1.2]}>
        <sphereGeometry args={[size * 0.12, 5, 4]} />
        <meshBasicMaterial color="#ffffff" />
      </mesh>
    </group>
  );
}

// ─── Eyebrow ──────────────────────────────────────────────
function Eyebrow({ x, y, z, width = 0.07, tilt = 0, expression }: {
  x: number; y: number; z: number; width?: number; tilt?: number; expression: Expression;
}) {
  const rotZ = expression === "sad" ? (x < 0 ? 0.25 : -0.25) + tilt
    : expression === "focused" ? (x < 0 ? -0.15 : 0.15) + tilt
    : tilt;
  return (
    <mesh position={[x, y, z]} rotation={[0, 0, rotZ]}>
      <boxGeometry args={[width, 0.016, 0.015]} />
      <meshStandardMaterial color="#5a3010" roughness={0.9} />
    </mesh>
  );
}

// ─── Expression Mouth ─────────────────────────────────────
function ExpressionMouth({ expression, x = 0, y = -0.1, z = 0.23, width = 0.1 }: {
  expression: Expression; x?: number; y?: number; z?: number; width?: number;
}) {
  const h = expression === "happy" ? 0.04 : expression === "sad" ? 0.03 : 0.022;
  const color = expression === "happy" ? "#C62828" : expression === "sad" ? "#5D4037" : "#8B0000";
  const curve = expression === "happy" ? 0.022 : expression === "sad" ? -0.022 : 0;

  return (
    <group position={[x, y, z]}>
      <mesh>
        <boxGeometry args={[width, h, 0.02]} />
        <meshStandardMaterial color={color} roughness={0.6} />
      </mesh>
      {/* Lips */}
      <mesh position={[0, h * 0.5, 0.005]}>
        <boxGeometry args={[width * 0.9, 0.012, 0.01]} />
        <meshStandardMaterial color="#c47060" roughness={0.5} />
      </mesh>
      {expression !== "neutral" && (
        <mesh position={[0, curve, 0.008]}>
          <boxGeometry args={[width * 0.65, 0.012, 0.01]} />
          <meshStandardMaterial color={color} roughness={0.6} />
        </mesh>
      )}
    </group>
  );
}

// ─── Body Component Interface ──────────────────────────────
interface BodyProps {
  characterId: string;
  outfit: MinionState["outfit"];
  animState: AnimState;
  isWorking: boolean;
  hovered: boolean;
  isSelected: boolean;
  accentColor: string;
  expression: Expression;
}

function PunakawanBody(props: BodyProps) {
  switch (props.characterId) {
    case "semar": return <SemarBody {...props} />;
    case "gareng": return <GarengBody {...props} />;
    case "petruk": return <PetrukBody {...props} />;
    case "bagong": return <BagongBody {...props} />;
    default: return <SemarBody {...props} />;
  }
}

