// ─── Breathing idle animation ──────────────────────────────
function useBreathing(ref: React.RefObject<THREE.Mesh | null>, animState: AnimState) {
  useFrame(({ clock }) => {
    if (!ref.current) return;
    if (animState === "idle") {
      const breathe = 1 + Math.sin(clock.getElapsedTime() * 1.4) * 0.025;
      ref.current.scale.set(1, breathe, 1);
    } else {
      ref.current.scale.set(1, 1, 1);
    }
  });
}

// ─── Shared Animation Hook ──────────────────────────────────
function useAnimations({
  leftArmRef, rightArmRef, leftLegRef, rightLegRef, animState, isWorking,
}: {
  leftArmRef: React.RefObject<THREE.Group | null>;
  rightArmRef: React.RefObject<THREE.Group | null>;
  leftLegRef: React.RefObject<THREE.Group | null>;
  rightLegRef: React.RefObject<THREE.Group | null>;
  animState: AnimState;
  isWorking: boolean;
}) {
  useFrame(({ clock }) => {
    const t = clock.getElapsedTime();

    if (animState === "walking") {
      const swing = Math.sin(t * 6) * 0.42;
      if (leftLegRef.current) leftLegRef.current.rotation.x = swing;
      if (rightLegRef.current) rightLegRef.current.rotation.x = -swing;
      if (leftArmRef.current) leftArmRef.current.rotation.x = -swing * 0.55;
      if (rightArmRef.current) rightArmRef.current.rotation.x = swing * 0.55;
    } else if (animState === "working" || isWorking) {
      if (leftArmRef.current) leftArmRef.current.rotation.x = Math.sin(t * 5) * 0.28 - 0.45;
      if (rightArmRef.current) rightArmRef.current.rotation.x = Math.sin(t * 5 + 1) * 0.28 - 0.45;
      if (leftLegRef.current) leftLegRef.current.rotation.x = 0;
      if (rightLegRef.current) rightLegRef.current.rotation.x = 0;
    } else {
      // Gentle idle sway
      const idle = Math.sin(t * 1.1) * 0.025;
      if (leftArmRef.current) leftArmRef.current.rotation.x = idle;
      if (rightArmRef.current) rightArmRef.current.rotation.x = -idle;
      if (leftLegRef.current) leftLegRef.current.rotation.x = 0;
      if (rightLegRef.current) rightLegRef.current.rotation.x = 0;
    }
  });
}
"}

