function skinMat(color: string, roughness = 0.75) {
  return <meshPhysicalMaterial color={color} roughness={roughness} metalness={0} reflectivity={0.1} />;
}
function clothMat(color: string) {
  return <meshPhysicalMaterial color={color} roughness={0.85} metalness={0} />;
}

// ─── Toon gradient texture (3-step cel shading) ────────────
const toonGradient = (() => {
  const data = new Uint8Array([50, 50, 50, 255, 148, 148, 148, 255, 255, 255, 255, 255]);
  const tex = new THREE.DataTexture(data, 3, 1, THREE.RGBAFormat);
  tex.minFilter = THREE.NearestFilter;
  tex.magFilter = THREE.NearestFilter;
  tex.needsUpdate = true;
  return tex;
})();

function toon(color: string, emissive = "#000000", emissiveIntensity = 0) {
  return <meshToonMaterial color={color} gradientMap={toonGradient} emissive={emissive} emissiveIntensity={emissiveIntensity} />;
}"}

