interface TraceEntry { minionId: string; prompt: string; status: string; cost: number; }

function readRecentTraces(hoursBack = 24): TraceEntry[] {
  if (!existsSync(TRACES_PATH)) return [];
  const cutoff = Date.now() - hoursBack * 60 * 60 * 1000;
  const entries: TraceEntry[] = [];

  try {
    const files = readdirSync(TRACES_PATH).filter(f => f.endsWith(".json"));
    for (const f of files) {
      // filename: trace-{minion}-{timestamp}.json
      const parts = f.replace(".json", "").split("-");
      const ts = parseInt(parts[parts.length - 1] || "0");
      if (ts < cutoff) continue;
      try {
        const raw = JSON.parse(readFileSync(resolve(TRACES_PATH, f), "utf-8"));
        entries.push({
          minionId: raw.minionId || "?",
          prompt: (raw.prompt || "").slice(0, 150),
          status: raw.status || "unknown",
          cost: raw.cost || 0,
        });
      } catch { /* skip corrupt files */ }
    }
  } catch { /* skip if dir unreadable */ }

  return entries.slice(-30); // max 30 entries for context
}

async function runDreamAnalysis(traces: TraceEntry[]): Promise<string> {
  const apiKey = process.env.CLAUDE_CODE_OAUTH_TOKEN;
  if (!apiKey) throw new Error("No API key");

  const activitySummary = traces.length > 0
    ? traces.map(t => `• [${t.minionId}] "${t.prompt.slice(0, 100)}" — ${t.status}`).join("\n")
    : "Tidak ada aktivitas tercatat.";

  const totalCost = traces.reduce((s, t) => s + t.cost, 0).toFixed(4);

  const prompt = `Aktivitas Punakawan dalam 24 jam terakhir (${traces.length} task, total biaya $${totalCost}):

${activitySummary}

Berikan laporan singkat dalam format berikut — HANYA output JSON valid ini:

{
  "refleksi": [
    "refleksi 1 — hal konkret yang bisa ditingkatkan",
    "refleksi 2 — hal konkret yang bisa ditingkatkan",
    "refleksi 3 — hal konkret yang bisa ditingkatkan"
  ],
  "ide_fitur": [
    "ide 1 — fitur agentic AI yang menarik",
    "ide 2 — fitur agentic AI yang menarik",
    "ide 3 — fitur agentic AI yang menarik"
  ],
  "ringkasan": "1-2 kalimat ringkasan hari ini"
}`;

  const res = await fetch(ANTHROPIC_API, {
    method: "POST",
    headers: { "x-api-key": apiKey, "anthropic-version": "2023-06-01", "Content-Type": "application/json" },
    body: JSON.stringify({
      model: CLAUDE_MODEL,
      max_tokens: 800,
      system: "Kamu adalah Semar yang sedang bermimpi — merenungkan hari yang telah berlalu dan memberi inspirasi untuk esok. Jawab HANYA dengan JSON valid.",
      messages: [{ role: "user", content: prompt }],
    }),
  });

  if (!res.ok) throw new Error(`Claude API ${res.status}`);
  const data = await res.json() as { content: Array<{ text: string }> };
  return data.content?.[0]?.text?.trim() || "{}";
}

function formatDreamReport(raw: string): string {
  try {
    const report = JSON.parse(raw) as { refleksi: string[]; ide_fitur: string[]; ringkasan: string };
    return [
      "🌙 *Laporan Mimpi Punakawan*",
      "",
      `_${report.ringkasan || "..."}_`,
      "",
      "🪬 *Refleksi Diri*",
      ...(report.refleksi || []).map((r, i) => `${i + 1}. ${r}`),
      "",
      "💡 *Ide Fitur*",
      ...(report.ide_fitur || []).map((r, i) => `${i + 1}. ${r}`),
    ].join("\n");
  } catch {
    return raw; // fallback raw text
  }
}

